#include <stdio.h>

void log_error(FILE* logfile, const char* error_msg) {
    if (logfile != NULL) {
        fprintf(logfile, "Error: %s\n", error_msg);
    }
}

int main() {
    FILE* log_file = fopen("error_log.txt", "a");
    if (log_file == NULL) {
        return 1;
    }

    const char* error_message = "An unexpected error occurred.";
    log_error(log_file, error_message);

    fclose(log_file);
    return 0;
}